from flask import Flask, request
import psycopg2
app = Flask(__name__)

@app.route('/query', methods=['GET'])
def dynamic_query():
    # get input from user
    table_name = request.args.get('table') 
    column_names = request.args.getlist('columns[]')  
    conditions = request.args.get('conditions')  
    
    # create connection
    conn = psycopg2.connect(database="your_database", user="user_name", password="password", host="127.0.0.1", port="5432") 
    cur = conn.cursor()
    
    # create dynamic SQL query 
    columns_str = ', '.join(column_names) if column_names else '*'  
    sql_query = f"SELECT {columns_str} FROM {table_name} WHERE {conditions};" if conditions else f"SELECT {columns_str} FROM {table_name};" 
    
    # execute query and fetch data
    cur.execute(sql_query)  
    result = [dict(row) for row in cur.fetchall()]
    conn.close()  # close the connection

    return {'data': result}

if __name__ == "__main__":
    app.run(port=5000, debug=True)